var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"인정할 수 없어...... 인정할 수 없어......","JPN":"認めない……認められないから……","ENG":"No... I can't accept this.","TWN":"我不相信……我不相信……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"관리국 카운터 아카데미는...... 인류의 영웅을 키워내는 곳이야.","JPN":"管理局カウンターアカデミーは……人類の英雄を育てる場所なの。","ENG":"The Counter Academy... is a place for training humanity's greatest heroes.","TWN":"管理局的制裁者學院……是培養人類英雄的地方。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"훈련도 제대로 안 받고 3류 태스크포스나 전전하다 온 주제에! 체계적인 교육을 받은 나보다 뛰어날 리 없잖아!","JPN":"まともな訓練も受けたこともなくて、三流タスクフォースカンパニーを転々としてきた分際で！　真面目に教育を受けてきた私より優れてるわけがない！","ENG":"She never got any training except from that third-rate TASKFORCE! There's no way she can best me, after all the elite training I've received!","TWN":"沒受過系統訓練，在3流特遣勢力混日子的傢伙！沒道理比我這樣受到系統教育的人強！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"......그래, 저건 시뮬레이터일 뿐이야. 진짜가 아니야.","JPN":"……そうよ、あれはシミュレーターにすぎない。本物じゃない。","ENG":"Right... That's just a simulator. It's not the real deal.","TWN":"……對，那個只是模擬器而已。不是真實的。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"진짜라면 내가 저 녀석보다 못할 리 없어.","JPN":"本物だったらあいつより私の方が上手くやれる。","ENG":"In real life, there's no way I'd fall behind her.","TWN":"如果是真實情況，我一定比那個傢伙強。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"거기 너! 결투를 신청한다! 시뮬레이터 따위가 아니라 현실에서......!","JPN":"あんたに決闘を挑むわ！　シミュレーターなんかじゃなくて、現実で……！","ENG":"Hey, you! I challenge you to a duel! Not in the simulator, but real life—","TWN":"你！我申請與你決鬥！不是什麼模擬器，而是在現實……！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"무, 무슨 소리지?","JPN":"な、なんの音？","ENG":"W-what was that?","TWN":"什、什麼聲音？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"침식체? 갑자기 어디서......!","JPN":"侵食体？　いきなりどこから……！","ENG":"A Corrupted Object? Where did it come from?","TWN":"侵蝕體？突然從哪裡冒出來的……!"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"거기서 뭐 하는 거야? 당장 대피하지 않고?!","JPN":"そこで何してるの！　今すぐ逃げて！","ENG":"What are you doing over there? You have to evacuate! Now!","TWN":"你們在幹嘛？快跑啊？！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"대피라니 웃기지 마! 난 네게 결투를 신청했다고!","JPN":"逃げる？　ふざけないで、私はあんたに決闘申請をしたの！","ENG":"Evacuate? Don't make me laugh! I just challenged you to a duel!","TWN":"跑？別搞笑了！我申請與你決鬥！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"너야말로 결투 같은 시대착오적인 헛소리 하지 마!","JPN":"あんたこそ状況をみて！　今は決闘どころじゃないよ！","ENG":"A duel? We're not in the 18th century, you moron!","TWN":"決鬥，你在胡說八道什麼！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"시뮬레이터가 폭주하고 있어! 어서 사람들을 대피시켜야 돼!","JPN":"シミュレーターが暴走してる！　はやく皆を避難させないと！","ENG":"The simulator is going berserk! We have to evacuate everyone!","TWN":"模擬器正在暴走！要讓其他人趕快撤離！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"시끄러워! 나한테 명령하지 마!","JPN":"うるさい！　私に命令しないで！","ENG":"Shut up! You can't boss me around!","TWN":"吵死了！別命令我！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"이 따위 가짜 침식체들은 언제든지 처리할 수 있어!","JPN":"こんな偽物の侵食体なんか、いくらでも相手にできるわ！","ENG":"I can take out these fake C.O.s anytime!","TWN":"這種假的侵蝕體，隨便就能處理掉！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그보다 결투를...... 꺄아악?!","JPN":"だから決闘を……きゃーっ！？","ENG":"But first, the duel... Eeek!","TWN":"決鬥才是……啊啊啊？！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"자, 잔챙이들 주제에! 당장 떨어지지 못 해?!","JPN":"ざ、雑魚のくせに！　離れろ！","ENG":"Y-you critters don't stand a chance against me! Get off me!","TWN":"你們這些小傢伙們！還不快滾開？！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};